// ─── SUPABASE DATA SYNC SERVICE ────────────────────────
// Provides utility functions to load and save data to Supabase

import { supabase } from './supabaseClient';

/**
 * Load all data from Supabase (products, categories, ads)
 * Falls back to provided initial data if Supabase is not configured
 */
export async function loadDataFromSupabase(initialData) {
  if (!supabase.ready) {
    console.log('ℹ️ Supabase not configured. Using local data.');
    return initialData;
  }

  try {
    console.log('📡 Loading data from Supabase...');
    const [products, categories, ads] = await Promise.all([
      supabase.getProducts().catch(() => []),
      supabase.getCategories().catch(() => []),
      supabase.getAds().catch(() => []),
    ]);

    return {
      products: products && products.length ? products : initialData.products,
      categories: categories && categories.length ? categories : initialData.categories,
      ads: ads && ads.length ? ads : initialData.ads,
    };
  } catch (error) {
    console.error('⚠️ Failed to load from Supabase:', error.message);
    console.log('📦 Using fallback local data');
    return initialData;
  }
}

/**
 * Sync a single product to Supabase
 * Returns the saved product or null if failed
 */
export async function syncProductToSupabase(product, action = 'add') {
  if (!supabase.ready) {
    console.log('ℹ️ Supabase not configured. Skipping sync.');
    return product;
  }

  try {
    if (action === 'add') {
      const result = await supabase.addProduct(product);
      console.log('✓ Product saved to Supabase:', result);
      return result?.[0] || product;
    } else if (action === 'update') {
      await supabase.updateProduct(product.id, product);
      console.log('✓ Product updated in Supabase:', product.id);
      return product;
    } else if (action === 'delete') {
      await supabase.deleteProduct(product.id);
      console.log('✓ Product deleted from Supabase:', product.id);
      return null;
    }
  } catch (error) {
    console.error(`⚠️ Failed to ${action} product:`, error.message);
    throw error;
  }
}

/**
 * Sync a single category to Supabase
 */
export async function syncCategoryToSupabase(category, action = 'add') {
  if (!supabase.ready) {
    console.log('ℹ️ Supabase not configured. Skipping sync.');
    return category;
  }

  try {
    if (action === 'add') {
      const result = await supabase.addCategory(category);
      console.log('✓ Category saved to Supabase:', result);
      return result?.[0] || category;
    } else if (action === 'update') {
