      console.log('✓ Category updated in Supabase:', category.id);
      return category;
    } else if (action === 'delete') {
      await supabase.deleteCategory(category.id);
      console.log('✓ Category deleted from Supabase:', category.id);
      return null;
    }
  } catch (error) {
    console.error(`⚠️ Failed to ${action} category:`, error.message);
    throw error;
  }
}

/**
 * Sync a single ad to Supabase
 */
export async function syncAdToSupabase(ad, action = 'add') {
  if (!supabase.ready) {
    console.log('ℹ️ Supabase not configured. Skipping sync.');
    return ad;
  }

  try {
    if (action === 'add') {
      const result = await supabase.addAd(ad);
      console.log('✓ Ad saved to Supabase:', result);
      return result?.[0] || ad;
    } else if (action === 'update') {
      await supabase.updateAd(ad.id, ad);
